"""Render Q&A results as readable markdown (examples + eval)."""
from __future__ import annotations
from collections import Counter
from typing import Iterable

from .guardrails import all_rules_brief


def _bullet(items: Iterable[str], indent: int = 0) -> str:
    pad = "  " * indent
    return "\n".join(f"{pad}- {x}" for x in items)


def render_examples(answers: list) -> str:
    """The 15 worked answers."""
    lines = [
        "# BCPD v2.1 State Q&A — Worked Examples\n",
        "_Generated by `financials/qa/bcpd_state_qa.py` (deterministic mode, no API)._\n",
        "_State: `output/operating_state_v2_1_bcpd.json` (schema_version `operating_state_v2_1_bcpd`)._\n",
        "\nThis is the canonical answer set for the 15 fixed test questions. Every answer cites its source files, declares its confidence, lists caveats, and reports any guardrail violations.\n",
        "\n---\n",
    ]
    for a in answers:
        lines.append(f"## Q{a.qid} — {a.question}\n")
        lines.append(f"**Category**: {a.category} · **Expected kind**: {a.expected_kind} · **Confidence**: `{a.confidence}` · **Mode**: {a.mode}\n")
        if a.cannot_conclude:
            lines.append("\n**`cannot_conclude` = true** — the harness refuses or caveats this question.\n")
        lines.append("\n### Answer\n")
        lines.append(a.direct_answer)
        lines.append("\n\n### Evidence\n")
        if a.evidence:
            for ev in a.evidence:
                lines.append(f"- {ev}")
        else:
            lines.append("- (none recorded)")
        lines.append("\n### Caveats\n")
        if a.caveats:
            for c in a.caveats:
                lines.append(f"- {c}")
        else:
            lines.append("- (none)")
        lines.append("\n### Source files used\n")
        for s in a.source_files_used:
            lines.append(f"- `{s}`")
        lines.append("\n### Guardrails triggered\n")
        if a.guardrails_triggered:
            for v in a.guardrails_triggered:
                lines.append(f"- **{v['guardrail']}** — {v['rule']}")
                if v.get("missing_required_phrases"):
                    lines.append(f"    - missing phrases: {v['missing_required_phrases']}")
                if v.get("forbidden_phrases_present"):
                    lines.append(f"    - forbidden phrases present: {v['forbidden_phrases_present']}")
        else:
            lines.append("- (none)")
        lines.append("\n---\n")
    return "\n".join(lines)


def render_eval(answers: list) -> str:
    """Eval summary of what worked, what didn't, and whether the harness validates the state-layer approach."""
    n = len(answers)
    by_conf = Counter(a.confidence for a in answers)
    by_cat = Counter(a.category for a in answers)
    refused = [a for a in answers if a.confidence == "refused" or a.cannot_conclude]
    inferred = [a for a in answers if a.confidence == "inferred"]
    high = [a for a in answers if a.confidence == "high"]
    triggered = [a for a in answers if a.guardrails_triggered]
    triggered_rules = Counter()
    for a in triggered:
        for v in a.guardrails_triggered:
            triggered_rules[v["guardrail"]] += 1

    md = []
    md.append("# BCPD v2.1 State Q&A — Eval\n\n")
    md.append("_Generated by `financials/qa/bcpd_state_qa.py`._\n\n")
    md.append("This eval reports on whether the v2.1 operating state, agent context, and supporting reports are sufficient for an LLM or deterministic retrieval layer to answer the 15 fixed business questions with evidence, confidence, caveats, and refusals.\n\n")
    md.append("---\n\n")

    md.append("## Headline\n\n")
    md.append(f"- **Questions answered**: {n}\n")
    md.append(f"- **Confidence distribution**: " + ", ".join(f"`{k}`={v}" for k, v in by_conf.most_common()) + "\n")
    md.append(f"- **Category distribution**: " + ", ".join(f"{k}={v}" for k, v in by_cat.most_common()) + "\n")
    md.append(f"- **Cannot-conclude / refused**: {len(refused)} ({', '.join(f'Q{a.qid}' for a in refused) or 'none'})\n")
    md.append(f"- **Guardrail violations**: {len(triggered)} answer(s)\n")
    md.append(f"- **Schema version**: `operating_state_v2_1_bcpd` (v2.1 default; v2.0 not loaded)\n\n")

    md.append("---\n\n")
    md.append("## Where the state answers well\n\n")
    md.append("- **Descriptive metadata** (Q1 scope, Q4 change log, Q10 open questions): high confidence; the v2.1 JSON carries explicit fields (`metadata`, `v2_1_changes_summary`, `source_owner_questions_open`) that make these direct lookups.\n")
    md.append("- **Self-aware semantics** (Q6 missing cost, Q11 SctLot, Q15 roadmap): the agent context and quality report give the harness exactly the language an answer should use, including the `missing != 0` rule and the SctLot reinterpretation.\n")
    md.append("- **Refusals** (Q7 org-wide): the state's caveat list and agent context's hard-limits section make refusal automatic; the harness returns `confidence='refused'` and `cannot_conclude=True`.\n")
    md.append("- **Coverage analytics** (Q2 strong, Q3 no-GL, Q14 ClickUp): per-project actuals and the `data_quality` block give clean numbers; the answer enumerates explicitly.\n")
    md.append("- **Trust boundaries** (Q8 lot grain, Q9 project/phase grain): the agent context's 5 enforced rules + the `vf_actual_cost_join_key` constant on every lot mean the harness can answer cleanly.\n\n")

    md.append("## Where answers are limited\n\n")
    md.append("- Per-lot dollar lookups are **inferred** by design (decoder-derived). The harness reports them as such — not a defect, but a label consumers must respect.\n")
    md.append("- Numerical questions about specific lots / phases (e.g. 'what is BCPD's actual cost for Parkway Fields Phase B1 Lot 112?') are not in the 15-question set; the harness's deterministic handlers do not compute these. They are demonstrated in `state_query_examples_v2_1_bcpd.md`.\n")
    md.append("- The harness does NOT validate that decoder-derived lot dollars match Lot Data; it inherits the W3 simulation results. Questions like 'show me a Harmony lot whose VF cost contradicts Lot Data' would require additional retrieval logic.\n")
    md.append("- Q11 (SctLot interpretation) and Q15 (data improvements) are inherently subjective; the harness states the v2.1 reading rather than ranking competing interpretations.\n\n")

    md.append("## Guardrails triggered\n\n")
    if not triggered:
        md.append("**None.** All 15 answers passed every applicable guardrail. This is the expected outcome — the harness was built specifically to reflect the agent context's enforcement rules.\n\n")
    else:
        md.append(f"{len(triggered)} answers had ≥1 guardrail violation. By rule:\n\n")
        md.append("| guardrail | violations | answers affected |\n|---|---:|---|\n")
        for rule, count in triggered_rules.most_common():
            affected = ", ".join(f"Q{a.qid}" for a in triggered if any(v["guardrail"] == rule for v in a.guardrails_triggered))
            md.append(f"| `{rule}` | {count} | {affected} |\n")
        md.append("\n")
    md.append("Full guardrail rule list:\n\n")
    for r in all_rules_brief():
        md.append(f"- **{r['name']}** — {r['rule']}\n")
    md.append("\n")

    md.append("---\n\n")
    md.append("## Strongest answers\n\n")
    md.append("Ranked by a combination of (a) high confidence, (b) precise evidence (specific JSON paths or numbers), and (c) zero guardrail violations:\n\n")
    for a in sorted(high, key=lambda a: a.qid):
        md.append(f"- **Q{a.qid}** ({a.category}) — {a.question} — `confidence={a.confidence}`, evidence fields cited.\n")
    md.append("\n")

    md.append("## Weakest answers\n\n")
    md.append("Ranked by (a) inferred confidence on a question that asks for cost numbers, and (b) `cannot_conclude=True`:\n\n")
    weakest_pool = inferred + refused
    seen = set()
    for a in sorted(weakest_pool, key=lambda a: a.qid):
        if a.qid in seen: continue
        seen.add(a.qid)
        flag = "refused" if a.cannot_conclude else "inferred"
        md.append(f"- **Q{a.qid}** ({a.category}) — {a.question} — `{flag}`. {('Cost numbers are decoder-derived; not source-owner-validated.' if flag == 'inferred' else 'Out-of-scope by design.')}\n")
    md.append("\n")

    md.append("---\n\n")
    md.append("## Does this validate the state-layer approach?\n\n")
    has_violations = bool(triggered)
    has_refusal = any(a.cannot_conclude for a in answers)
    has_inferred_label = any(a.confidence == "inferred" for a in answers)
    citations_complete = all(a.source_files_used for a in answers)
    if (not has_violations) and has_refusal and has_inferred_label and citations_complete:
        md.append("**Yes.** Every condition is met:\n\n")
        md.append("- All 15 answers cite specific source files (the state JSON plus relevant context/report markdown).\n")
        md.append("- Unsupported questions (org-wide actuals; Q7) are explicitly refused with `cannot_conclude=True` rather than fabricated.\n")
        md.append("- Decoder-derived numbers ship with `confidence='inferred'`, preserving the v2.1 honesty contract.\n")
        md.append("- No guardrail rule was violated by the deterministic answer set, which means the agent context's rules are internally consistent with the state's data.\n")
        md.append("- v2.1 was loaded as the default; v2.0 was not loaded (the loader hard-fails on schema mismatch).\n\n")
        md.append("**Conclusion**: the v2.1 state + agent context + reports provide enough structured signal that a deterministic retrieval layer can answer the 15 questions correctly. An LLM layer reading the same artifacts has no excuse to invent numbers, conflate phases, or report missing cost as zero — every required disambiguation is encoded explicitly. The state layer is doing its job.\n\n")
    else:
        md.append("**Partially.**\n\n")
        if has_violations:
            md.append(f"- {len(triggered)} answers tripped at least one guardrail. This usually means the answer text doesn't cover a required phrase that the corresponding agent-context rule demands. Either the answer needs more language, or the guardrail's `must_appear` list is too strict.\n")
        if not has_refusal:
            md.append("- No question was refused. If Q7 (org-wide) didn't refuse, the harness is over-reaching.\n")
        if not has_inferred_label:
            md.append("- No `inferred` labels surfaced. This is suspicious — decoder-derived per-lot cost should be inferred.\n")
        if not citations_complete:
            md.append("- One or more answers lack source-file citations. Every answer should reference at least the state JSON.\n")
        md.append("\n")
    md.append("---\n\n")
    md.append("## Demo readiness\n\n")
    if (not has_violations) and has_refusal and has_inferred_label and citations_complete:
        md.append("**Yes — demo-ready.** The harness can be run end-to-end against the v2.1 state and produces an examples document and an eval document that surface confidence labels, refusal behavior, evidence trails, and guardrail compliance. A reviewer reading `output/bcpd_state_qa_examples.md` and `output/bcpd_state_qa_eval.md` can quickly verify that the v2.1 state is consumable by an agent layer without leaking incorrect numbers.\n")
    else:
        md.append("Not yet — see the issues called out above.\n")
    md.append("\n")
    return "".join(md)
